# NL HMB.  Hoorn - Medemblik
#
let hm = path("d3.nl.hmb");

with detail = 3,
     railway = :second :museum
{
    # point.nl.Hoorn  nl.ZEH

    with link = "line.nl.HMB" {
        track(:ror, hm[:hoo + 329m, :hko - 0.49sw] << 0.5md << 1ms << 0.5mt);
    }

    with link = "point.nl.Hoorn-Koepoortsweg" {
        track(hm[:hko - 0.5sw, :hko + 0.5sw] << 0.5md << 1ms << 0.5mt);
        marker(:left :de.hp :removed,
            hm[:hko] << 0.5md << 1ms << 1mt, hm[:hko] << 0.5md << 1ms
        );
    }

    with link = "line.nl.HMB" {
        track(
                hm[:hko + 0.49sw, :hoo.ym] << 0.5md << 1ms << 0.5mt
            ..  hm[:hoo.xm + 1md, :wbl - 0.49sw]
        );
    }

    with link = "point.nl.Westerblokker" {
        track(hm[:wbl - 0.5sw, :wbl + 0.5sw]);
        marker(:left :de.hp :removed, hm[:wbl] << 0.5mt);
    }

    with link = "line.nl.HMB" {
        track(hm[:wbl + 0.49sw, :zwa - 0.49sw]);
    }

    with link = "point.nl.Zwaag" {
        track(hm[:zwa - 0.5sw, :zwa + 0.5sw]);
        marker(:right :de.bbf :nopax, hm[:zwa] >> 0.5mt);
        marker(:right :de.exbf :nopax, hm[:zwa] >> 0.5mt);
        slabel(:left :nopax, hm[:zwa] << 0.5dt + (-1.3dt, 1dt), "Zwaag");
    }

    with link = "line.nl.HMB" {
        track(hm[:zwa + 0.49sw, :zwd - 0.49sw]);
    }

    with link = "point.nl.Zwaagdijk" {
        track(hm[:zwd - 0.5sw, :zwd + 0.5sw]);
        marker(:left :de.hp :removed, hm[:zwd] << 0.5mt);
        slabel(:right :removed, hm[:zwd] >> 0.5mt + (1.8dt, 0.5dt),
            "Zwaagdijk"
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:zwd + 0.49sw, :zwd + 0.81km]);
        line_label(:right:sw, hm[:zwd + 0.8km] >> 0.5mt, "HMB");
        track(hm[:zwd + 0.79km, :wog - 0.49sw]);
    }

    with link = "point.nl.Wognum-Nibbixwoud" {
        track(hm[:wog - 0.5sw, :wog + 0.5sw]);
        marker(:left :de.bf, hm[:wog] << 0.5mt);
        slabel(:left, hm[:wog] << 0.5mt << 1sh + (-0.8dt, 0dt),
            vbox(:right:middle, "Wognum-", "Nibbixwoud ")
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:wog + 0.49sw, :wij - 0.49sw]);
    }

    with link = "point.nl.Wijzend" {
        track(hm[:wij - 0.5sw, :wij + 0.5sw]);
        marker(:left :de.hp :removed, hm[:wij] << 0.5mt);
        slabel(:right :removed, hm[:wij] >> 0.5mt + (1.0dt, 0.9dt),
            "Wijzend"
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:wij + 0.49sw, :ben - 0.49sw]);
    }

    with link = "point.nl.Benningbroek-Sijbekarspel" {
        track(hm[:ben - 0.5sw, :ben + 0.5sw]);
        marker(:right :de.bf :removed, hm[:ben] >> 0.5mt);
        slabel(:right :removed, hm[:ben] >> 0.5mt >> 1sh + (1.2dt, 0dt),
            vbox(:left:middle, "Benningbroek-", "Sijbekarspel")
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:ben + 0.49sw, :abb - 0.49sw]);
    }

    with link = "point.nl.Abbekerk-Lambertschaag" {
        track(hm[:abb - 0.5sw, :abb + 0.5sw]);
        marker(:left :de.bf :removed, hm[:abb] << 0.5mt);
        slabel(:left :removed, hm[:abb] << 0.5mt << 1sh + (-1dt, 0.8dt),
            vbox(:right:middle, "Abbekerk- ", "Lambertschaag")
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:abb + 0.49sw, :mwo - 0.49sw]);
    }

    with link = "point.nl.Midwoud-Oostwoud" {
        track(hm[:mwo - 0.5sw, :mwo + 0.5sw]);
        marker(:right :de.bbf :nopax, hm[:mwo] >> 0.5mt);
        marker(:right :de.exbf :nopax, hm[:mwo] >> 0.5mt);
        slabel(:bottom :nopax, hm[:mwo] >> 0.5mt >> 1.4sh + (1dt, 0.9dt),
            vbox(:center:topbase, " Midwoud-", "Oostwoud")
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:mwo + 0.49sw, :twi - 0.49sw]);
    }

    with link = "point.nl.Twisk" {
        track(hm[:twi - 0.5sw, :twi + 0.5sw]);
        marker(:left :de.bf, hm[:twi] << 0.5mt);
        slabel(:left, hm[:twi] << 0.5mt << 1sh + (-1.3dt, 1.2dt),
            "Twisk"
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:twi + 0.49sw, :opp - 0.49sw]);
    }

    with link = "point.nl.Opperdoes" {
        track(hm[:opp - 0.5sw, :opp + 0.5sw]);
        marker(:right :de.bf, hm[:opp] >> 0.5mt);
        slabel(:left, hm[:opp] << 0.5mt + (-1.3dt, 0dt),
            "Opperdoes"
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:opp + 0.49sw, :opo - 0.49sw]);
    }

    with link = "point.nl.Opperdoes-Oosteinde" {
        track(hm[:opo - 0.5sw, :opo + 0.5sw]);
        marker(:left :de.hp :removed, hm[:opo] << 0.5mt);
        slabel(:left :removed, hm[:opo] << 0.5mt << 1sh + (-1.3dt, 0.5dt),
            "Opperdoes-Oosteinde"
       );
    }

    with link = "line.nl.HMB" {
        track(hm[:opo + 0.49sw, :opo + 0.61km]);
        line_label(:right:nw, hm[:opo + 0.6km] >> 0.5mt, "HMB");
        track(hm[:opo + 0.59km, :med - 0.49sw]);
    }

    with link = "point.nl.Medemblik" {
        track(hm[:med - 0.5sw, :med + 0.5sw]);
        marker(:right :de.bf, hm[:med] >> 0.5mt);
        slabel(:top :bold, hm[:med] << 0.5mt + (0dt, -0.3dt),
            "Medemblik"
       );
    }
}

